import (
	"github.com/openmeterio/openmeter/pkg/lrux"
)

cache, err := lrux.NewCacheWithItemTTL(
	1000,
	func(ctx context.Context, id string) (Entity, error) { return repo.Get(ctx, id) },
	lrux.WithTTL(30*time.Second),
)
if err != nil {
	return err
}
v, err := cache.Get(ctx, id)

